#include <stdio.h>

int main() {
    int T; if (scanf("%d", &T) != 1) return 0;
    while (T--) {
        long long N, M; scanf("%lld%lld", &N, &M);
        if (M == -1) {
            printf("-1\n");
        } else {
            long long ans = N - M; // (N-M+1)-1
            printf("%lld\n", ans);
        }
    }
    return 0;
}

