code.Python3:
#!/usr/bin/env python3
import sys

def main():
    data = sys.stdin.read().strip().split()
    if not data:
        return
    it = iter(data)
    T = int(next(it))
    out = []
    for _ in range(T):
        N = int(next(it))
        M = int(next(it))
        if M == -1:
            out.append("-1")
        else:
            out.append(str(N - M))  # (N-M+1)-1
    sys.stdout.write("\n".join(out))

if __name__ == "__main__":
    main()

